  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return 1; // Connection failed
  }
  auto conn = *conn_result;

  // 2. Start a transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return 1; // Transaction start failed
  }

  // 3. Build and execute the delete operation with where condition
  auto delete_result = (sqlgen::delete_from<User> 
                       | sqlgen::where("last_login"_c < "2025-01-01"))(conn);

  if (!delete_result) {
    conn->rollback();
    return 1; // Delete operation failed
  }

  // 4. Commit the transaction
  auto commit_result = conn->commit();

  // 5. Return the commit result
  return commit_result ? 0 : 1;
}

} // namespace delete_inactive_users
