  }
  auto conn = *conn_result;

  // 2. Construct the first UPDATE statement for expired orders
  auto update_expired = update<Order>("status"_c.set("expired"))
                       | where("status"_c == "pending" && 
                              "order_date"_c < (sqlgen::transpilation::Operation<
                                  sqlgen::transpilation::Operator::date_plus_duration,
                                  sqlgen::transpilation::Value<std::string>{"now"},
                                  sqlgen::transpilation::Value<std::string>{"-7 days"}{}));

  // 3. Construct the second UPDATE statement for delivered orders
  auto update_delivered = update<Order>("status"_c.set("delivered"))
                         | where("status"_c == "shipped");

  // 4. Execute both updates and return total affected rows
  int total_affected = 0;

  // Execute first update
  auto result1 = update_expired(conn);
  if (result1) {
    total_affected += result1.value();
  }

  // Execute second update  
  auto result2 = update_delivered(conn);
  if (result2) {
    total_affected += result2.value();
  }

  return total_affected;
}

