                                    sqlgen::count("user_id2"_t3) | sqlgen::as<"mutual_friends">)
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user1_id"_t3)
    | sqlgen::inner_join<Friendship, "f2">("user_id2"_t3 == "user1_id"_t4)
    | sqlgen::inner_join<User, "u2">("user_id2"_t4 == "user_id"_t2)
    | sqlgen::where("user_id"_t1 < "user_id"_t2 && 
                    sqlgen::exists(
                      sqlgen::select_from<Friendship, "f3">()
                        | sqlgen::where("user_id1"_t5 == "user_id"_t1 && 
