                    ))
    | sqlgen::group_by("user_id"_t1, "user_id"_t2)
    | sqlgen::having(sqlgen::count("user_id2"_t3) > 0)
    | sqlgen::to<std::vector<FriendConnection>>;

  // Query 2: Users with more than average friends using nested query
  auto average_friends_query = 
    sqlgen::select_from<User, "u">("user_id"_t1, "username"_t1,
                                   sqlgen::count("user_id2"_t2) | sqlgen::as<"friend_count">)
    | sqlgen::left_join<Friendship, "f">("user_id"_t1 == "user1_id"_t2)
    | sqlgen::group_by("user_id"_t1, "username"_t1)
    | sqlgen::having(sqlgen::count("user_id2"_t2) > 
                     sqlgen::avg(sqlgen::select_from<Friendship, "f_avg">(
                                sqlgen::count("user_id2"_t3) 
                                | sqlgen::group_by("user1_id"_t3))
                                .to<double>()))
    | sqlgen::order_by(sqlgen::desc(sqlgen::count("user_id2"_t2)))
    | sqlgen::to<std::vector<UserStats>>;

  // Execute queries and return results
  auto mutual_results = mutual_friends_query(conn).value();
  auto average_results = average_friends_query(conn).value();

