 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create an update statement for the Note table
  auto update_stmt = sqlgen::update<Note>(
    // Use the set function to replace the content column
    sqlgen::literals::operator""_c<"content">().set(
      // Use string operations to replace "foo" with "bar"
      sqlgen::literals::operator""_c<"content">().like("%foo%") 
        ? sqlgen::literals::operator""_c<"content">().replace("foo", "bar")
        : sqlgen::literals::operator""_c<"content">()
    )
  );

  // Execute the update statement
