  auto updated_notes_result = sqlgen::read<std::vector<UpdatedNote>>(conn);

  // Transform the results to match the UpdatedNote structure
  std::vector<UpdatedNote> updated_notes;
  for (const auto& note : updated_notes_result.value()) {
    updated_notes.push_back({
        .note_id = note.note_id,
        .updated_content = note.content
    });
  }

  return updated_notes;
}

