/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // Create in-memory database connection
  auto conn = sqlgen::sqlite::connect(":memory:").value();

  // Create temporary tables
  conn->execute("CREATE TEMPORARY TABLE Department (department_id INTEGER PRIMARY KEY, department_name TEXT NOT NULL, location TEXT)").value();
  conn->execute("CREATE TEMPORARY TABLE Employee (employee_id INTEGER PRIMARY KEY, department_id INTEGER, first_name TEXT NOT NULL, last_name TEXT NOT NULL, salary REAL NOT NULL)").value();

  // Insert data
  sqlgen::write(depts)(conn).value();
  sqlgen::write(emps)(conn).value();

  // Build and execute join queries
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_d | sqlgen::as<"department_name">,
      "first_name"_e | sqlgen::as<"first_name">,
      "last_name"_e | sqlgen::as<"last_name">,
      "salary"_e | sqlgen::as<"salary">
  ) | sqlgen::inner_join<Employee, "e">("department_id"_d == "department_id"_e)
    | sqlgen::to<std::vector<JoinResult>>;

  auto left_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d | sqlgen::as<"department_name">,
      "first_name"_e | sqlgen::as<"first_name">,
      "last_name"_e | sqlgen::as<"last_name">,
      "salary"_e | sqlgen::as<"salary">
  ) | sqlgen::left_join<Department, "d">("department_id"_e == "department_id"_d)
    | sqlgen::to<std::vector<JoinResult>>;

  auto right_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d | sqlgen::as<"department_name">,
      "first_name"_e | sqlgen::as<"first_name">,
      "last_name"_e | sqlgen::as<"last_name">,
      "salary"_e | sqlgen::as<"salary">
  ) | sqlgen::right_join<Department, "d">("department_id"_e == "department_id"_d)
    | sqlgen::to<std::vector<JoinResult>>;

  auto full_query = sqlgen::select_from<Department, "d">(
      "department_name"_d | sqlgen::as<"department_name">,
      "first_name"_e | sqlgen::as<"first_name">,
      "last_name"_e | sqlgen::as<"last_name">,
      "salary"_e | sqlgen::as<"salary">
  ) | sqlgen::full_join<Employee, "e">("department_id"_d == "department_id"_e)
    | sqlgen::to<std::vector<JoinResult>>;

  // Execute queries and populate results
  auto inner_result = inner_query(conn).value();
  auto left_result = left_query(conn).value();
  auto right_result = right_query(conn).value();
  auto full_result = full_query(conn).value();

  // Build and return analysis
  JoinAnalysis analysis;
  analysis.inner_join_results = std::move(inner_result);
  analysis.left_join_results = std::move(left_result);
  analysis.right_join_results = std::move(right_result);
  analysis.full_join_results = std::move(full_result);

  return analysis;
}

}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect(":memory:")` to create an in-memory SQLite database connection.

2. **Temporary Table Creation**: Creates temporary tables using `CREATE TEMPORARY TABLE` SQL statements with proper column definitions matching the struct definitions.

3. **Data Insertion**: Uses `sqlgen::write()` to insert the provided department and employee data into the temporary tables.

4. **Join Queries**: Implements all four join types using sqlgen's fluent interface:
   - **Inner Join**: Matches departments with employees where department_id equals employee's department_id
   - **Left Join**: Includes all employees and their departments (if exists)
   - **Right Join**: Includes all departments and their employees (if exists)
   - **Full Join**: Includes all employees and departments regardless of matches

5. **Result Mapping**: Uses `sqlgen::to<std::vector<JoinResult>>` to automatically map query results to the `JoinResult` struct with proper optional field handling for NULL values.

6. **Error Handling**: Uses `.value()` to extract results from `Result` types, assuming successful execution for this implementation context.

The implementation follows sqlgen's principles of using a fluent API with operator overloading (`|`) to build complex SQL queries in a type-safe manner while maintaining the library's functional programming style.

