  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen::literals;

  // 1. Create database connection
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {}; // Return empty vector on connection failure
  }
  auto conn = *conn_result;

  // 2. Build the query using sqlgen's fluent interface
  auto query = sqlgen::select_from<User>("user_id"_c, "name"_c)
      | sqlgen::inner_join<Post>("user_id"_c == "user_id"_c)
      | sqlgen::group_by("user_id"_c, "name"_c)
      | sqlgen::select_from<User>("user_id"_c, "name"_c, 
